135	async function freePort(): Promise<number> {
136		return new Promise((resolve, reject) => {
137			const server = net.createServer();
138			server.once('error', reject);
139			server.listen(0, '127.0.0.1', () => {
140				const address = server.address();
141				if (!address || typeof address === 'string') {
142					server.close(() => reject(new Error('could not allocate port')));
143					return;
144				}
145				const port = address.port;
146				server.close(() => resolve(port));
147			});
148		});
