247	async function stopRealDdxServer(server: RealServer) {
248		await server.api.dispose();
249		if (server.process.exitCode === null) {
250			server.process.kill();
251			await Promise.race([
252				new Promise((resolve) => server.process.once('exit', resolve)),
253				new Promise((resolve) => {
254					setTimeout(() => {
255						if (server.process.exitCode === null) server.process.kill('SIGKILL');
256						resolve(undefined);
257					}, 2000);
258				})
259			]);
260		}
261		fs.rmSync(server.root, { recursive: true, force: true });
262	}
