107	<div class="flex flex-col gap-4" style="height: calc(100dvh - 40px - 3rem)">
108		<div class="flex shrink-0 items-center justify-between">
109			<div class="flex items-center gap-3">
110				<h1 class="text-xl font-semibold dark:text-white">Document Graph</h1>
111				{#if issues.length > 0}
112					<span
113						data-testid="integrity-badge"
114						class="rounded-full bg-amber-200 px-2 py-0.5 text-xs font-medium text-amber-900 dark:bg-amber-800 dark:text-amber-100"
115					>
116						{issues.length}
117						{issues.length === 1 ? 'issue' : 'issues'}
118					</span>
119				{/if}
120			</div>
121			<div class="flex items-center gap-4">
122				<a
123					href={`/nodes/${$page.params['nodeId']}/projects/${$page.params['projectId']}/artifacts?mediaType=text%2Fmarkdown`}
124					class="text-sm text-accent-lever hover:underline dark:text-dark-accent-lever"
125				>
126					Back to documents
127				</a>
128				<span class="text-sm text-gray-700 dark:text-gray-300">
129					{visibleNodes.length} nodes &middot; {visibleLinks.length} edges
130				</span>
131			</div>
132		</div>
133	
134		<!-- Filter chips -->
135		<div class="flex shrink-0 flex-wrap gap-2">
136			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Type:</span>
137			{#each MEDIA_TYPE_CHIPS as chip}
138				{@const active = activeMediaTypes.includes(chip.value)}
139				<button
140					onclick={() => toggleMediaType(chip.value)}
141					data-testid={`filter-mediatype-${chip.value.replace(/[^a-z]/gi, '-')}`}
142					class="rounded-full px-3 py-0.5 font-label-caps text-label-caps uppercase transition-colors {active
143						? 'bg-accent-lever text-white dark:bg-dark-accent-lever'
144						: 'bg-bg-surface text-fg-muted hover:bg-bg-elevated hover:text-fg-ink dark:bg-dark-bg-surface dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink'}"
145				>
146					{chip.label}
147				</button>
148			{/each}
149			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Staleness:</span>
150			{#each STALENESS_CHIPS as chip}
151				{@const active = activeStaleness.includes(chip.value)}
152				<button
153					onclick={() => toggleStaleness(chip.value)}
154					data-testid={`filter-staleness-${chip.value}`}
155					class="rounded-full px-3 py-0.5 font-label-caps text-label-caps uppercase transition-colors {active
156						? 'bg-accent-lever text-white dark:bg-dark-accent-lever'
157						: 'bg-bg-surface text-fg-muted hover:bg-bg-elevated hover:text-fg-ink dark:bg-dark-bg-surface dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink'}"
158				>
159					{chip.label}
160				</button>
161			{/each}
162		</div>
163	
164		{#if issues.length > 0}
165			<IntegrityPanel {issues} pathToDocId={data.graph.pathToDocId} />
166		{/if}
167	
168		{#if data.graph.documents.length === 0}
169			<div class="flex flex-1 items-center justify-center text-gray-700 dark:text-gray-300">
170				No documents in graph.
171			</div>
172		{:else}
173			<div class="min-h-0 flex-1 overflow-hidden rounded-lg border border-gray-200 dark:border-gray-700">
174				<D3Graph
175					nodes={visibleNodes}
176					links={visibleLinks}
177					onNodeClick={handleNodeClick}
178					initialTransform={data.initialTransform}
179					onTransformChange={handleTransformChange}
180					highlightNodeId={data.highlightNodeId}
181				/>
182			</div>
183		{/if}
184	</div>
